parameters.jsCode:
const items = [];
const emails = Array.isArray($input.all()) ? $input.all() : [$input.first()];
for (const email of emails) {
  const subject = email.json.subject || '';
  const snippet = email.json.snippet || '';
  const body = email.json.text || email.json.html || '';

  // Try to extract item title from subject (Vinted subjects are like "Tvůj item 'TITLE' byl prodán")
  const titleMatch = subject.match(/'([^']+)'/) || subject.match(/"([^"]+)"/);
  const title = titleMatch ? titleMatch[1] : snippet.substring(0, 60);

  // Try to extract price from body/snippet
  const priceMatch = (body + snippet).match(/(\d+)\s*(?:Kč|CZK|czk|kč)/i);
  const salePrice = priceMatch ? parseInt(priceMatch[1]) : 0;

  // Try to extract Vinted item ID from email links
  const vintedIdMatch = (body + snippet).match(/vinted\.cz\/items\/(\d+)/);
  const vintedId = vintedIdMatch ? vintedIdMatch[1] : '';

  items.push({ json: { title, salePrice, vintedId, emailSubject: subject, emailDate: email.json.date || new Date().toISOString() } });
}
return items;

const emailData = $('Parse Email').item.json;
const sheetRow = $input.first().json;
const fbUrl = sheetRow['FB URL'] || sheetRow['B'] || 'Not found';
const title = sheetRow['Title'] || sheetRow['D'] || emailData.title;
const fbPrice = sheetRow['FB Price'] || sheetRow['F'] || 0;
const vintedPrice = sheetRow['Vinted Price'] || sheetRow['G'] || 0;
const profit = emailData.salePrice ? emailData.salePrice - parseInt(fbPrice) : vintedPrice - parseInt(fbPrice);
return [{ json: { title, fbUrl, salePrice: emailData.salePrice, profit, vintedId: emailData.vintedId, fbPrice, vintedPrice, emailData } }];

